VALUES
  ('cpa-moex-01301', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '龍潭公司承租一座購物中心，包含土地及地上建物，有關租賃分類之下列敘述，何者錯誤？', '["最低租賃給付應按租賃開始日土地及建築物之公允價值相對比例分攤予土地及建築物", "若租賃給付無法可靠地分攤至此兩項要素，則整體租賃應分類為融資租賃，除非二項要素均明顯 符合營業租賃標準", "如土地要素之原始認列金額不重大，則土地及建築物可按單一項目處理", "若龍潭公司將該購物中心分類為投資性不動產，則應以融資租賃方式處理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01302', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '丁公司採確定福利退休計畫，20X7年底退休計畫相關項目如下： 確定福利義務現值  $8,000,000 計畫資產公允價值  5,000,000 未攤銷前期服務成本  1,000,000 未攤銷精算利益  2,500,000 應計退休金負債  4,500,000 該公司於20X8年初以計畫資產$1,000,000購買年金合約，以清償全部既得給付義務$l,000,000。則購 買年金合約以清償既得福利義務之事項，對20X8年應計退休金負債影響為何？', '["增加$187,500", "增加$1,000,000", "減少$187,500", "減少$1,000,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01303', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X3年初修改退休辦法，使確定福利義務現值增加$1,794,000。甲公司目前在職員工共 80人，其相關資料如下： 至符合既得福利條件日剩餘服務年限  1  2  3  4  5 員工人數  10  20  30  10  10 假設甲公司以員工符合既得福利條件之平均剩餘服務年限攤銷前期服務成本，則20X6年應分攤之前 期服務成本為若干？', '["$0", "$156,000", "$224,250", "$624,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01304', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司長期工程合約原採成本回收法（或稱零利潤法），20X6 年改採完工百分比法，相關資料 如下： 成本回收法 完工百分比法 20X6年期初在建工程   $250,000 $350,000 20X6年期末在建工程   260,000 400,000 若20X6年初原列保留盈餘為$500,000，稅率為30%，則此一長期工程損益認列方法之改變，20X6 年初之保留盈餘應作之調整為何？', '["增加$70,000", "增加$100,000", "增加$140,000", "不需調整"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01305', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年初取得乙公司15%的股權，並列為備供出售金融資產（透過其他綜合損益按公允 價值衡量之金融資產）；另於20X4年初再取得乙公司15%的股權，致對乙公司營運具重大影響力。 20X3年底甲公司帳列金融資產未實現利益為$50,000，該公司並無其他股權投資。若乙公司淨資產帳 面值皆等於公允價值，其20X4年淨利為$500,000，則投資乙公司30%股權對甲公司20X4年本期損 益之影響為何？', '["增加$75,000", "增加$100,000", "增加$150,000", "增加$200,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01306', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '下列何者不會導致銷貨毛利率下降？', '["商品存貨之成本降低比例小於售價調降比例", "為增加市場競爭力而調降售價", "銷貨毛利較低之商品占整體商品之銷售比例上升", "因商品存貨成本上升而等比例調升售價"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01307', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司20X1年以每股42元購入乙公司普通股股票100,000股，並分類為備供出售金融資產。該 股票於20X1年底公允價值為每股44元。甲公司於20X2年3月初以每股42元將該股票全數賣出。 下列有關此項股票交易對甲公司綜合損益表影響之敘述，何者正確？', '["對20X1年之本期淨利影響為0元", "對20X2年之本期淨利影響為0元", "對20X1年之本期綜合損益影響為0元", "對20X2年之本期綜合損益影響為0元 對20X2年之其他綜合損益影響為0元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01308', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '以下關於存貨的會計處理，何者正確：', '["附買回合約之銷貨，該商品非市場上隨時可得，賣方不認列銷貨收入，存貨仍列為資產，於取得 現金時認列負債，並於附註說明存貨抵押借款的事實", "高退貨率商品之銷貨，應待銷貨退回金額確定後，再依淨額認列銷貨收入", "分期付款的銷貨，若於貸款繳清前商品的所有權仍為賣方所擁有，此時即便商品已經交付買方， 賣方仍不得將商品自存貨中扣除", "個別認定法可適用於非大量生產且不可替換之存貨 性質與用途類似之存貨，應就(a)平均法，(b)先進先出法，(c)後進先出法三種成本公式，一致採用 相同的成本公式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01309', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於20X1年初將當年年底到期，帳面金額為$500,000，分類為持有供交易金融資產之債券投資 售予乙公司，並提供最高賠償$40,000之違約損失保證。出售日該保證之公允價值為$25,000，乙公司 共支付$525,000予甲公司。甲公司並未移轉或保留該債券投資之幾乎所有風險及報酬，且約定乙公司 不得自由出售該債券。若20X1年底該債券投資未發生違約，關於甲公司20X1年對該債券投資應作 之會計處理，下列敘述何者正確？', '["應認列之移轉資產持續參與範圍金額共計為$25,000", "應認列之相關負債金額共計為$65,000", "應除列之金融資產金額共計為$475,000", "應認列之金融資產評價損益金額共計為$25,000 應認列之財務保證收入金額共計為$25,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01310', 'cpa', 'cpa-moex-103-78566e18', 'sub-cpa-01', NULL, 'single_choice', '高雄公司於20X1年12月31日發行可轉換公司債，面額$100,000，發行金額$110,000，直接交易 成本$2,200。已知當日不含轉換權之公司債公允價值為$90,000，轉換權之公允價值為$30,000。若發 行日負債組成部分之課稅基礎等於負債及權益組成部分原始帳面金額之合計數，稅率為 20%，對財 務報表項目之淨影響為何？', '["手續費$2,200", "應付公司債淨額$88,350", "遞延所得稅費用$3,980", "資本公積－可轉換公司債$19,450 遞延所得稅負債$3,890"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:14+00:00", "source_pdf_sha1": "5ea07b090de5", "answer_pdf_sha1": "9924e7044cbb", "source_family": "moex-gov-tw", "moex": {"exam_code": "103130", "c": "803", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "103", "exam_name": "103年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
